// ──────────────────────────────────────────────────────────────────────
// Cosmos DB provider – EF Core 9 breaking-change fixes
// Apply these patterns in your Cosmos DB project.
// ──────────────────────────────────────────────────────────────────────
using Microsoft.EntityFrameworkCore;
using Microsoft.Azure.Cosmos;

// ── FIX 1 — Discriminator property renamed from "Discriminator" to "$type" ──
// EF Core 9 defaults to "$type". Existing documents still store "Discriminator".
// Explicitly preserve the old name so existing documents keep working.

class CosmosDbContext : DbContext
{
    public DbSet<CosmosOrder> Orders => Set<CosmosOrder>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=...",
            "MyDatabase",
            cosmosOptions =>
            {
                // FIX 2 — Synchronous I/O now throws by default.
                // Best practice: convert all queries to async (ToListAsync, etc.).
                // If you cannot migrate yet, opt back in:
                cosmosOptions.AllowSynchronousIO(true);
            });
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX 1 — Keep the legacy discriminator property name for existing documents
        modelBuilder.Entity<CosmosOrder>()
            .HasDiscriminator<string>("Discriminator");
    }
}

class CosmosOrder
{
    public string Id { get; set; } = default!;
    public DateTime CreatedAt { get; set; }
}

